Greedy insertion with cost-benefit evaluation across all vehicles, falling back to a dedicated new assign if no feasible insertion improves or maintains low marginal cost.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e18
		insertSucceeded := false

		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			oldCost := dispatch.Assigns[ii].Cost
			if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
				dispatch.Assigns[ii].GenRoute()
				newCost := dispatch.Assigns[ii].Cost
				if newCost >= 0 {
					costDelta := newCost - oldCost
					if costDelta < bestCostDelta {
						bestCostDelta = costDelta
						bestAssignIdx = ii
						insertSucceeded = true
					}
				}
				dispatch.Assigns[ii].RemoveShip(total_ship + jj)
				dispatch.Assigns[ii].GenRoute()
			}
		}

		if insertSucceeded {
			dispatch.Assigns[bestAssignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[bestAssignIdx].GenRoute()
		} else {
			if dispatch.AssignsLen < MAXASSIGNS {
				idx := dispatch.AssignsLen
				if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[idx].GenRoute()
					dispatch.AssignsLen++
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

