algorithm:
Greedy insertion with regret heuristic and fallback seed expansion: for each unassigned ship, evaluate all feasible inserts across existing non-empty routes plus one potential new empty route, choosing the insert with minimum marginal cost increase; if none feasible, create a new assign if under capacity, otherwise force-insert into the least‑violation route and repair.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		assignIdx int
		delta     float64
		feasible  bool
	}
	orderCount := len(oris)
	for jj := 0; jj < orderCount; jj++ {
		bestCand := candidate{-1, 1e18, false}
		// Evaluate all existing assigns
		for idx := 0; idx < dispatch.AssignsLen; idx++ {
			a := &dispatch.Assigns[idx]
			oldCost := a.Cost
			ok := a.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				a.GenRoute()
				newCost := a.Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < bestCand.delta {
						bestCand.assignIdx = idx
						bestCand.delta = delta
						bestCand.feasible = true
					}
				}
				a.RemoveShip(total_ship + jj)
				a.GenRoute()
			}
		}
		// Also consider a new empty assign as fallback candidate
		newIdx := dispatch.AssignsLen
		if newIdx < MAXASSIGNS {
			tempAssign := dispatch.Assigns[newIdx]
			ok := tempAssign.AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				tempAssign.GenRoute()
				newCost := tempAssign.Cost
				if newCost >= 0 {
					delta := newCost
					if delta < bestCand.delta {
						bestCand.assignIdx = newIdx
						bestCand.delta = delta
						bestCand.feasible = true
					}
				}
				tempAssign.RemoveShip(total_ship + jj)
				tempAssign.GenRoute()
			}
		}
		if bestCand.feasible {
			targetIdx := bestCand.assignIdx
			if targetIdx == dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
			dispatch.Assigns[targetIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[targetIdx].GenRoute()
		} else {
			// Force fallback: pick first assign that accepts even if violates soft constraints
			inserted := false
			for idx := 0; idx < dispatch.AssignsLen; idx++ {
				if dispatch.Assigns[idx].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[idx].GenRoute()
					inserted = true
					break
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.Assigns[dispatch.AssignsLen].AddShip(total_ship+jj, oris[jj], dess[jj])
				dispatch.Assigns[dispatch.AssignsLen].GenRoute()
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

