func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})

	assignCandidates := make([]int, dispatch.AssignsLen+len(oris))
	candidateCount := 0
	for i := 0; i < dispatch.AssignsLen; i++ {
		assignCandidates[candidateCount] = i
		candidateCount++
	}
	for candidateCount < len(assignCandidates) {
		assignCandidates[candidateCount] = -1
		candidateCount++
	}
	newAssignStartIdx := dispatch.AssignsLen

	for _, idx := range orderIndices {
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		shuffledCandidates := make([]int, len(assignCandidates))
		copy(shuffledCandidates, assignCandidates)
		rand.Shuffle(len(shuffledCandidates), func(i, j int) {
			shuffledCandidates[i], shuffledCandidates[j] = shuffledCandidates[j], shuffledCandidates[i]
		})

		for _, cand := range shuffledCandidates {
			targetIdx := cand
			isNew := false
			if targetIdx == -1 || targetIdx >= dispatch.AssignsLen {
				if newAssignStartIdx < MAXASSIGNS {
					targetIdx = newAssignStartIdx
					isNew = true
				} else {
					continue
				}
			}

			oldCost := dispatch.Assigns[targetIdx].Cost
			addOk := dispatch.Assigns[targetIdx].AddShip(total_ship+idx, oris[idx], dess[idx])
			if !addOk {
				dispatch.Assigns[targetIdx].Cost = -1
			} else {
				dispatch.Assigns[targetIdx].GenRoute()
			}

			insertSuccess := dispatch.Assigns[targetIdx].Cost >= 0
			if insertSuccess {
				delta := dispatch.Assigns[targetIdx].Cost - oldCost
				if delta < bestDelta {
					bestDelta = delta
					bestAssignIdx = targetIdx
					if isNew {
						assignCandidates[len(assignCandidates)-1-(newAssignStartIdx-dispatch.AssignsLen)] = targetIdx
					}
				}
				dispatch.Assigns[targetIdx].RemoveShip(total_ship + idx)
				dispatch.Assigns[targetIdx].GenRoute()
			} else if isNew {
				dispatch.Assigns[targetIdx].RemoveShip(total_ship + idx)
				dispatch.Assigns[targetIdx].GenRoute()
			}
		}

		finalTarget := bestAssignIdx
		if finalTarget == -1 {
			fallbackIdx := newAssignStartIdx
			if fallbackIdx < MAXASSIGNS {
				finalTarget = fallbackIdx
			} else {
				for i := 0; i < dispatch.AssignsLen; i++ {
					fallbackIdx = i
					break
				}
				finalTarget = fallbackIdx
			}
		}

		addOk := dispatch.Assigns[finalTarget].AddShip(total_ship+idx, oris[idx], dess[idx])
		if !addOk {
			dispatch.Assigns[finalTarget].Cost = -1
		} else {
			dispatch.Assigns[finalTarget].GenRoute()
		}
		if dispatch.Assigns[finalTarget].Cost >= 0 {
			if finalTarget >= dispatch.AssignsLen {
				dispatch.AssignsLen = finalTarget + 1
				if newAssignStartIdx <= finalTarget {
					newAssignStartIdx = finalTarget + 1
				}
			}
		} else {
			dispatch.Assigns[finalTarget].RemoveShip(total_ship + idx)
			dispatch.Assigns[finalTarget].GenRoute()
			if finalTarget >= dispatch.AssignsLen && finalTarget < MAXASSIGNS {
				assignCandidates[len(assignCandidates)-1-(finalTarget-dispatch.AssignsLen)] = finalTarget
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

